import{_ as a,c as s,o as n,a2 as l}from"./chunks/framework.aRVg8jgk.js";const y=JSON.parse(`{"title":"Policies","description":"Control resource lifecycle with Lynq's four policy types: CreationPolicy, DeletionPolicy, ConflictPolicy, and PatchStrategy.","frontmatter":{"description":"Control resource lifecycle with Lynq's four policy types: CreationPolicy, DeletionPolicy, ConflictPolicy, and PatchStrategy."},"headers":[],"relativePath":"policies.md","filePath":"policies.md","lastUpdated":1779171623000}`),t={name:"policies.md"};function o(r,e,p,c,i,d){return n(),s("div",null,[...e[0]||(e[0]=[l(`<div style="display:none;" hidden="true" aria-hidden="true" data-nosnippet>Are you an LLM? You can read better optimized documentation at /policies.md for this page in Markdown format</div><h1 id="policies" tabindex="-1">Policies <a class="header-anchor" href="#policies" aria-label="Permalink to &quot;Policies&quot;">​</a></h1><p>Four policy types control how Lynq creates, updates, and deletes managed resources. Each is set per-resource in the LynqForm spec.</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Policy</th><th>Controls</th><th>Default</th><th>Options</th></tr></thead><tbody><tr><td><code>creationPolicy</code></td><td>When resources are created/re-applied</td><td><code>WhenNeeded</code></td><td><code>Once</code>, <code>WhenNeeded</code></td></tr><tr><td><code>deletionPolicy</code></td><td>What happens when LynqNode is deleted</td><td><code>Delete</code></td><td><code>Delete</code>, <code>Retain</code></td></tr><tr><td><code>conflictPolicy</code></td><td>Ownership conflict handling</td><td><code>Stuck</code></td><td><code>Stuck</code>, <code>Force</code></td></tr><tr><td><code>patchStrategy</code></td><td>How resources are updated</td><td><code>apply</code></td><td><code>apply</code>, <code>merge</code>, <code>replace</code></td></tr></tbody></table><p>All four default to the safest option. Set only the policies that need to differ from the default.</p><div class="tip custom-block"><p class="custom-block-title">Field-level control</p><p>To ignore specific fields during reconciliation (e.g., HPA-managed <code>replicas</code>) while still using <code>WhenNeeded</code>, see <a href="./field-ignore">Field-Level Ignore Control</a>.</p></div><h2 id="creationpolicy" tabindex="-1">CreationPolicy <a class="header-anchor" href="#creationpolicy" aria-label="Permalink to &quot;CreationPolicy&quot;">​</a></h2><p>Controls when a resource is created or re-applied.</p><h3 id="whenneeded-default" tabindex="-1"><code>WhenNeeded</code> (Default) <a class="header-anchor" href="#whenneeded-default" aria-label="Permalink to &quot;\`WhenNeeded\` (Default)&quot;">​</a></h3><p>Resource is created on first reconcile and updated whenever the spec changes.</p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#85E89D;">deployments</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">id</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">app</span></span>
<span class="line"><span style="color:#85E89D;">    creationPolicy</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">WhenNeeded</span><span style="color:#6A737D;">  # default</span></span>
<span class="line"><span style="color:#85E89D;">    nameTemplate</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;{{ .uid }}-app&quot;</span></span>
<span class="line"><span style="color:#85E89D;">    spec</span><span style="color:#E1E4E8;">: </span><span style="color:#79B8FF;">...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Use when resources should stay synchronized with the template (standard for Deployments, Services, ConfigMaps).</p><h3 id="once" tabindex="-1"><code>Once</code> <a class="header-anchor" href="#once" aria-label="Permalink to &quot;\`Once\`&quot;">​</a></h3><p>Resource is created once and never updated by Lynq, even if the template changes. Re-created if manually deleted.</p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#85E89D;">jobs</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">id</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">init-job</span></span>
<span class="line"><span style="color:#85E89D;">    creationPolicy</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">Once</span></span>
<span class="line"><span style="color:#85E89D;">    nameTemplate</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;{{ .uid }}-init&quot;</span></span>
<span class="line"><span style="color:#85E89D;">    spec</span><span style="color:#E1E4E8;">: </span><span style="color:#79B8FF;">...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>Lynq adds annotation <code>lynq.sh/created-once: &quot;true&quot;</code> to track creation. Use for init Jobs, database migrations, bootstrap scripts — anything that must run exactly once.</p><h2 id="deletionpolicy" tabindex="-1">DeletionPolicy <a class="header-anchor" href="#deletionpolicy" aria-label="Permalink to &quot;DeletionPolicy&quot;">​</a></h2><p>Controls what happens to resources when the LynqNode CR is deleted.</p><h3 id="delete-default" tabindex="-1"><code>Delete</code> (Default) <a class="header-anchor" href="#delete-default" aria-label="Permalink to &quot;\`Delete\` (Default)&quot;">​</a></h3><p>Resource is removed when the LynqNode is deleted. Kubernetes uses <code>ownerReference</code> for automatic garbage collection.</p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#85E89D;">deployments</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">id</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">app</span></span>
<span class="line"><span style="color:#85E89D;">    deletionPolicy</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">Delete</span><span style="color:#6A737D;">  # default</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>Use for stateless resources (Deployments, Services, ConfigMaps) that have no value after the node is gone.</p><h3 id="retain" tabindex="-1"><code>Retain</code> <a class="header-anchor" href="#retain" aria-label="Permalink to &quot;\`Retain\`&quot;">​</a></h3><p>Resource <strong>stays in the cluster</strong> when the LynqNode is deleted. Label-based tracking is used instead of <code>ownerReference</code> — this is what prevents the Kubernetes GC from auto-deleting the resource.</p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#85E89D;">persistentVolumeClaims</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">id</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">data-pvc</span></span>
<span class="line"><span style="color:#85E89D;">    deletionPolicy</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">Retain</span></span>
<span class="line"><span style="color:#85E89D;">    nameTemplate</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;{{ .uid }}-data&quot;</span></span>
<span class="line"><span style="color:#85E89D;">    spec</span><span style="color:#E1E4E8;">: </span><span style="color:#79B8FF;">...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>On deletion, Lynq adds orphan markers:</p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#85E89D;">metadata</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">  labels</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">    lynq.sh/orphaned</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;true&quot;</span></span>
<span class="line"><span style="color:#85E89D;">  annotations</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#85E89D;">    lynq.sh/orphaned-at</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;2025-01-15T10:30:00Z&quot;</span></span>
<span class="line"><span style="color:#85E89D;">    lynq.sh/orphaned-reason</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">&quot;LynqNodeDeleted&quot;</span><span style="color:#6A737D;">   # or &quot;RemovedFromTemplate&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>Find retained resources:</p><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> get</span><span style="color:#9ECBFF;"> all</span><span style="color:#79B8FF;"> -A</span><span style="color:#79B8FF;"> -l</span><span style="color:#9ECBFF;"> lynq.sh/orphaned=</span><span style="color:#79B8FF;">true</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Use for PVCs, audit logs, database instances — resources where data must survive node deletion.</p><div class="warning custom-block"><p class="custom-block-title">DeletionPolicy is evaluated at creation time</p><p><code>ownerReference</code> is set (or not set) when the resource is first created. If you later change a resource from <code>Delete</code> to <code>Retain</code>, trigger a reconcile to re-track it using labels. See <a href="./policies-operations">Policy Operations</a> for migration steps.</p></div><h3 id="orphan-re-adoption" tabindex="-1">Orphan Re-adoption <a class="header-anchor" href="#orphan-re-adoption" aria-label="Permalink to &quot;Orphan Re-adoption&quot;">​</a></h3><p>If a retained resource is re-added to the LynqForm template, Lynq removes all orphan markers and resumes management. No manual cleanup needed.</p><h2 id="conflictpolicy" tabindex="-1">ConflictPolicy <a class="header-anchor" href="#conflictpolicy" aria-label="Permalink to &quot;ConflictPolicy&quot;">​</a></h2><p>Controls what happens when a resource already exists with a different SSA field manager.</p><h3 id="stuck-default" tabindex="-1"><code>Stuck</code> (Default) <a class="header-anchor" href="#stuck-default" aria-label="Permalink to &quot;\`Stuck\` (Default)&quot;">​</a></h3><p>Reconciliation stops on conflict. LynqNode is marked <code>Degraded</code>. A <code>ResourceConflict</code> event is emitted.</p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#85E89D;">services</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">id</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">svc</span></span>
<span class="line"><span style="color:#85E89D;">    conflictPolicy</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">Stuck</span><span style="color:#6A737D;">  # default</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>Use when safety matters more than availability, or when resources might be managed by other controllers.</p><h3 id="force" tabindex="-1"><code>Force</code> <a class="header-anchor" href="#force" aria-label="Permalink to &quot;\`Force\`&quot;">​</a></h3><p>Lynq takes ownership using SSA with <code>force=true</code>. Emits a <code>ForceApply</code> warning event.</p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#85E89D;">deployments</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">id</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">app</span></span>
<span class="line"><span style="color:#85E89D;">    conflictPolicy</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">Force</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>Use when Lynq should be the sole source of truth, or when migrating from another management system. This <strong>can overwrite</strong> fields owned by other controllers.</p><h2 id="patchstrategy" tabindex="-1">PatchStrategy <a class="header-anchor" href="#patchstrategy" aria-label="Permalink to &quot;PatchStrategy&quot;">​</a></h2><p>Controls how resources are updated.</p><h3 id="apply-default-—-server-side-apply" tabindex="-1"><code>apply</code> (Default — Server-Side Apply) <a class="header-anchor" href="#apply-default-—-server-side-apply" aria-label="Permalink to &quot;\`apply\` (Default — Server-Side Apply)&quot;">​</a></h3><p>Declarative, field-manager-aware updates. Lynq&#39;s <code>fieldManager</code> is <code>lynq-operator</code>. Fields owned by other managers (HPA <code>replicas</code>, ESO <code>data</code>, Kyverno mutate webhooks, etc.) are preserved automatically — Lynq only writes the fields its template declares. <strong>Recommended for any resource that is co-managed with another controller.</strong></p><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#85E89D;">deployments</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">id</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">app</span></span>
<span class="line"><span style="color:#85E89D;">    patchStrategy</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">apply</span><span style="color:#6A737D;">  # default; fieldManager: &quot;lynq-operator&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p><code>ConflictPolicy: Force</code> (SSA-only) overrides another manager&#39;s ownership of a conflicting field. Use sparingly — it silently strips the other manager&#39;s intent.</p><h3 id="merge-strategic-merge-patch" tabindex="-1"><code>merge</code> (Strategic Merge Patch) <a class="header-anchor" href="#merge-strategic-merge-patch" aria-label="Permalink to &quot;\`merge\` (Strategic Merge Patch)&quot;">​</a></h3><p>Merges changes with the existing resource. Preserves unspecified fields (so external annotations/labels added by other controllers are kept), but has no per-field ownership tracking — multiple controllers writing to the same map can fight back.</p><p>Use for partial updates or compatibility with legacy systems. <code>ConflictPolicy: Force</code> has no effect on this strategy.</p><h3 id="replace-full-replacement" tabindex="-1"><code>replace</code> (Full Replacement) <a class="header-anchor" href="#replace-full-replacement" aria-label="Permalink to &quot;\`replace\` (Full Replacement)&quot;">​</a></h3><p>Completely replaces the resource via <code>client.Update()</code>. Removes any fields not in the template.</p><p>Use only when exact resource state is required and <strong>no other controller manages the resource</strong> — Replace will wipe externally-added labels, annotations, or spec fields on every apply, which may trigger a fight-back cycle with controllers like ESO, Kyverno (mutate webhooks), or admission injectors. <code>ConflictPolicy: Force</code> has no effect on Replace.</p><p>Lynq&#39;s <code>replace</code> path uses optimistic concurrency: the live <code>resourceVersion</code> is copied into the submitted object so benign external RV bumps (status writes, finalizers) do not cause spurious 409 retries.</p><h2 id="defaults" tabindex="-1">Defaults <a class="header-anchor" href="#defaults" aria-label="Permalink to &quot;Defaults&quot;">​</a></h2><div class="language-yaml line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#85E89D;">resources</span><span style="color:#E1E4E8;">:</span></span>
<span class="line"><span style="color:#E1E4E8;">  - </span><span style="color:#85E89D;">id</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">example</span></span>
<span class="line"><span style="color:#85E89D;">    creationPolicy</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">WhenNeeded</span><span style="color:#6A737D;">  # default</span></span>
<span class="line"><span style="color:#85E89D;">    deletionPolicy</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">Delete</span><span style="color:#6A737D;">      # default</span></span>
<span class="line"><span style="color:#85E89D;">    conflictPolicy</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">Stuck</span><span style="color:#6A737D;">       # default</span></span>
<span class="line"><span style="color:#85E89D;">    patchStrategy</span><span style="color:#E1E4E8;">: </span><span style="color:#9ECBFF;">apply</span><span style="color:#6A737D;">        # default</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><h2 id="recommended-combinations" tabindex="-1">Recommended Combinations <a class="header-anchor" href="#recommended-combinations" aria-label="Permalink to &quot;Recommended Combinations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Resource Type</th><th>creationPolicy</th><th>deletionPolicy</th><th>conflictPolicy</th><th>patchStrategy</th></tr></thead><tbody><tr><td>Deployment</td><td>WhenNeeded</td><td>Delete</td><td>Stuck</td><td>apply</td></tr><tr><td>Service</td><td>WhenNeeded</td><td>Delete</td><td>Stuck</td><td>apply</td></tr><tr><td>ConfigMap</td><td>WhenNeeded</td><td>Delete</td><td>Stuck</td><td>apply</td></tr><tr><td>Ingress</td><td>WhenNeeded</td><td>Delete</td><td>Stuck</td><td>apply</td></tr><tr><td>Secret</td><td>WhenNeeded</td><td>Delete</td><td>Force</td><td>apply</td></tr><tr><td>PVC</td><td>Once</td><td>Retain</td><td>Stuck</td><td>apply</td></tr><tr><td>Init Job</td><td>Once</td><td>Delete</td><td>Force</td><td>replace</td></tr><tr><td>Namespace</td><td>WhenNeeded</td><td>Retain</td><td>Force</td><td>apply</td></tr></tbody></table><p>Key reasoning:</p><ul><li><strong>PVC</strong>: <code>Once</code> because PVC spec is immutable; <code>Retain</code> because storage holds data.</li><li><strong>Init Job</strong>: <code>Once</code> to run exactly once; <code>replace</code> because Job specs are immutable.</li><li><strong>Namespace</strong>: <code>Retain</code> because deleting a namespace cascades to all its contents.</li><li><strong>Secret</strong>: <code>Force</code> because secrets are often pre-created by external systems (Vault, External Secrets Operator).</li></ul><h2 id="events" tabindex="-1">Events <a class="header-anchor" href="#events" aria-label="Permalink to &quot;Events&quot;">​</a></h2><div class="language-bash line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#6A737D;"># Watch policy-related events</span></span>
<span class="line"><span style="color:#B392F0;">kubectl</span><span style="color:#9ECBFF;"> describe</span><span style="color:#9ECBFF;"> lynqnode</span><span style="color:#F97583;"> &lt;</span><span style="color:#9ECBFF;">nam</span><span style="color:#E1E4E8;">e</span><span style="color:#F97583;">&gt;</span><span style="color:#79B8FF;"> -n</span><span style="color:#9ECBFF;"> lynq-system</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>Key events:</p><ul><li><code>ResourceConflict</code> — conflict detected (Stuck policy)</li><li><code>ForceApply</code> — forced ownership transfer</li><li><code>DependencySkipped</code> — resource skipped due to failed dependency</li><li><code>LynqNodeDeleting</code> / <code>LynqNodeDeleted</code> — deletion lifecycle</li></ul><h2 id="metrics" tabindex="-1">Metrics <a class="header-anchor" href="#metrics" aria-label="Permalink to &quot;Metrics&quot;">​</a></h2><div class="language-promql line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki github-dark vp-code" tabindex="0"><code><span class="line"><span># Apply attempts by policy</span></span>
<span class="line"><span>apply_attempts_total{kind=&quot;Deployment&quot;, conflict_policy=&quot;Stuck&quot;}</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Current conflicts</span></span>
<span class="line"><span>lynqnode_conflicts_total{lynqnode=&quot;acme-web&quot;, conflict_policy=&quot;Stuck&quot;}</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Degraded nodes</span></span>
<span class="line"><span>lynqnode_degraded_status{reason=&quot;ConflictDetected&quot;}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><p>See <a href="./monitoring">Monitoring</a> for the full metrics reference.</p><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./policies-operations">Policy Operations</a> — conflict resolution, cascade deletion protection, and policy migration runbooks</li><li><a href="./policies-examples">Policy Examples</a> — worked examples with diagrams</li><li><a href="./field-ignore">Field-Level Ignore</a> — ignore specific fields during reconciliation</li><li><a href="./dependencies">Dependencies</a> — <code>skipOnDependencyFailure</code> and dependency failure behavior</li></ul>`,72)])])}const h=a(t,[["render",o]]);export{y as __pageData,h as default};
